const input = $('When Called').item.json;
const history = $('Get Conversation History').all().map(item => item.json);
const tickets = $('Get Open Tickets').all().map(item => item.json);

// Count tenant messages only (not Julia AI responses)
const tenantMessages = history.filter(m => m.sender !== 'Julia AI');
const messageCount = tenantMessages.length; // includes current message logged earlier

// Format conversation history (reverse to chronological)
const historyText = history.reverse().map(m => {
  const role = m.sender === 'Julia AI' ? 'Julia' : 'Tenant';
  return role + ': ' + (m.message_text || '');
}).join('\n');

// Format open tickets
const ticketsText = tickets.length > 0 && tickets[0].json !== undefined
  ? tickets.filter(t => t.ticket_id).map(t => '- ' + t.ticket_id + ': ' + t.category + ' - ' + t.summary + ' (' + t.status + ')').join('\n')
  : 'No open tickets';

const contextMessage = '## Tenant Info\n' +
  'Name: ' + (input.tenant_name || '') + '\n' +
  'Unit: ' + (input.unit || '') + '\n' +
  'Property: ' + (input.property || '') + '\n' +
  'Language: ' + (input.language_pref || 'fr') + '\n' +
  'Channel: ' + (input.channel || '') + '\n\n' +
  '## Message Count\n' +
  'This is tenant message #' + messageCount + ' in this conversation.\n' +
  'You have 3 exchanges total to diagnose and resolve.\n' +
  (messageCount >= 3 ? 'THIS IS THE FINAL MESSAGE. You MUST wrap up now.\n' : '') + '\n' +
  '## Open Tickets\n' + ticketsText + '\n\n' +
  '## Recent Conversation\n' + (historyText || 'No previous messages') + '\n\n' +
  '## Current Message\n' + (input.message || '');

return {
  json: {
    ...input,
    context_message: contextMessage,
    history_text: historyText,
    tickets_text: ticketsText,
    message_count: messageCount
  }
};

const input = $('When Called').item.json;
const aiOutput = $('Julia AI').item.json.response || $('Julia AI').item.json.text || '';

return {
  json: {
    ...input,
    response_text: aiOutput,
    channel: input.channel,
    chat_id: input.chat_id,
    phone: input.phone,
    email: input.email,
    tenant_name: input.tenant_name
  }
};

