const messages = $('Link Messages to Ticket').all().map(m => m.json);
const convo = messages
  .filter(m => m.sender !== 'Julia AI')
  .sort((a, b) => new Date(a.created_at) - new Date(b.created_at))
  .map(m => m.message_text || '')
  .join('\n');
const ticketId = $('Generate Ticket').item.json.ticket_id;
return { json: { ticket_id: ticketId, full_conversation: convo } };

